mapper.select:
SELECT
    #{memberId} AS member_id,
    IFNULL((
        SELECT SUM(pay_amount)
        FROM oms_order
        WHERE member_id = #{memberId}
          AND (delete_status IS NULL OR delete_status = 0)
          AND status IN (1, 2, 3)
    ), 0) AS consume_amount,
    IFNULL((
        SELECT SUM(coupon_amount)
        FROM oms_order
        WHERE member_id = #{memberId}
          AND (delete_status IS NULL OR delete_status = 0)
          AND status IN (1, 2, 3)
    ), 0) AS coupon_amount,
    IFNULL((
        SELECT COUNT(*)
        FROM oms_order
        WHERE member_id = #{memberId}
          AND (delete_status IS NULL OR delete_status = 0)
          AND status IN (1, 2, 3)
    ), 0) AS order_count,
    IFNULL((
        SELECT COUNT(*)
        FROM sms_coupon_history
        WHERE member_id = #{memberId}
    ), 0) AS coupon_count,
    IFNULL((
        SELECT COUNT(*)
        FROM pms_spu_comment c
        INNER JOIN ums_member m ON c.member_nick_name = m.nickname
        WHERE m.id = #{memberId}
    ), 0) AS comment_count,
    IFNULL((
        SELECT COUNT(*)
        FROM oms_order_return_apply ra
        INNER JOIN oms_order o ON ra.order_id = o.id
        WHERE o.member_id = #{memberId}
    ), 0) AS return_order_count,
    IFNULL((
        SELECT COUNT(*)
        FROM ums_member_login_log
        WHERE member_id = #{memberId}
    ), 0) AS login_count,
    0 AS attend_count,
    0 AS fans_count,
    IFNULL((
        SELECT COUNT(*)
        FROM ums_member_collect_spu
        WHERE member_id = #{memberId}
    ), 0) AS collect_product_count,
    IFNULL((
        SELECT COUNT(*)
        FROM ums_member_collect_subject
        WHERE member_id = #{memberId}
    ), 0) AS collect_subject_count,
    0 AS collect_comment_count,
    0 AS invite_friend_count
